use std::sync::mpsc;
use std::thread;
use std::time::Duration;

fn main() {
    let (tx, rx) = mpsc::channel();

    let mut handles = vec![];

    for i in 0..5 {
        let tx = tx.clone();
        let handle = thread::spawn(move || {
            let msg = format!("Message from thread {i}");
            tx.send(msg).unwrap();
        });
        handles.push(handle);
    }

    drop(tx);

    for msg in rx {
        println!("Received: {msg}");
    }

    for handle in handles {
        handle.join().unwrap();
    }
}
